import React, { useState } from 'react';

const AisleFinder = () => {
  const [file, setFile] = useState(null);
  const [textInput, setTextInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [groceryList, setGroceryList] = useState('');
  const [error, setError] = useState('');
  const [zipCode, setZipCode] = useState('');
  const [stores, setStores] = useState([]);
  const [selectedStore, setSelectedStore] = useState(null);
  const [storeSearchLoading, setStoreSearchLoading] = useState(false);

  const handleFileUpload = (event) => {
    const selectedFile = event.target.files[0];
    if (selectedFile && selectedFile.type === 'text/plain') {
      setFile(selectedFile);
      setError('');
    } else {
      setError('Please select a valid text file');
      setFile(null);
    }
  };

  const searchStores = async () => {
    if (!zipCode.trim()) {
      setError('Please enter a zip code');
      return;
    }

    setStoreSearchLoading(true);
    setError('');

    try {
      const response = await fetch('http://localhost:5001/api/find-stores', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ zipCode: zipCode.trim() }),
      });

      if (!response.ok) {
        throw new Error('Failed to search stores');
      }

      const result = await response.json();
      setStores(result.stores || []);

      if (result.stores && result.stores.length > 0) {
        setSelectedStore(result.stores[0]); // Auto-select first store
      }
    } catch (err) {
      setError('Error searching stores: ' + err.message);
      setStores([]);
    } finally {
      setStoreSearchLoading(false);
    }
  };

  const processGroceryList = async () => {
    if (!file && !textInput.trim()) {
      setError('Please select a file or enter grocery items');
      return;
    }

    setLoading(true);
    setError('');

    try {
      const formData = new FormData();

      if (file) {
        formData.append('file', file);
      } else {
        // Create a blob from text input
        const blob = new Blob([textInput], { type: 'text/plain' });
        formData.append('file', blob, 'grocery-list.txt');
      }

      formData.append('output_format', 'aisle');
      formData.append('store_id', selectedStore ? selectedStore.id : '01400943');
      formData.append('store', selectedStore ? selectedStore.name : '4500S Smiths');

      const response = await fetch('http://localhost:5001/api/process-grocery-list', {
        method: 'POST',
        body: formData,
      });

      if (!response.ok) {
        throw new Error('Failed to process grocery list');
      }

      const result = await response.text();
      setGroceryList(result);
    } catch (err) {
      setError('Error processing grocery list: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = async () => {
    try {
      await navigator.clipboard.writeText(groceryList);
      alert('Grocery list copied to clipboard!');
    } catch (err) {
      setError('Failed to copy to clipboard');
    }
  };

  return (
    <div style={{ 
      minHeight: '100vh', 
      backgroundColor: 'white',
      padding: '20px',
      fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif"
    }}>
      <div style={{ maxWidth: '900px', margin: '0 auto' }}>
        {/* Header */}
        <div style={{ 
          textAlign: 'center', 
          marginBottom: '40px',
          backgroundColor: '#90EE90',
          padding: '20px',
          borderRadius: '12px',
          boxShadow: '0 4px 15px rgba(144, 238, 144, 0.3)'
        }}>
          <h1 style={{ 
            color: '#2c3e50', 
            margin: '0', 
            fontSize: '3rem',
            fontWeight: '700',
            display: 'flex', 
            alignItems: 'center', 
            justifyContent: 'center', 
            gap: '15px' 
          }}>
            🥕 Aisle Finder 🥕
          </h1>
        </div>

        {/* How it works card */}
        <div style={{ 
          marginBottom: '30px', 
          padding: '25px', 
          backgroundColor: '#f8f9fa', 
          borderRadius: '12px', 
          textAlign: 'center',
          boxShadow: '0 4px 15px rgba(0,0,0,0.05)',
          border: '1px solid #e9ecef'
        }}>
          <h3 style={{ margin: '0 0 15px 0', color: '#2c3e50', fontSize: '1.3rem', fontWeight: '600' }}>
            ✨ How it works
          </h3>
          <p style={{ margin: '0 0 10px 0', fontSize: '16px', color: '#5a6c7d', lineHeight: '1.6' }}>
            Find your store then enter items in the text box or upload a file.
          </p>
          <p style={{ margin: '0', fontSize: '16px', color: '#5a6c7d', lineHeight: '1.6' }}>
            Each line should contain one grocery item. The app will then organize items by store aisle or by category for efficient shopping.
          </p>
        </div>

        {/* Store Finder Section */}
        <div style={{ 
          marginBottom: '30px', 
          padding: '25px', 
          backgroundColor: '#f8f9fa', 
          borderRadius: '12px',
          boxShadow: '0 4px 15px rgba(0,0,0,0.05)',
          border: '1px solid #e9ecef'
        }}>
          <h3 style={{ margin: '0 0 20px 0', color: '#2c3e50', fontSize: '1.3rem', fontWeight: '600', display: 'flex', alignItems: 'center', gap: '10px' }}>
            <img src="https://logos-world.net/wp-content/uploads/2020/04/Kroger-Logo.png" alt="Kroger" style={{ height: '24px' }} />
            Find My Store
          </h3>

          <div style={{ display: 'flex', gap: '15px', alignItems: 'flex-start', marginBottom: '20px', flexWrap: 'wrap' }}>
            <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
              <input
                type="text"
                value={zipCode}
                onChange={(e) => setZipCode(e.target.value)}
                placeholder="Enter ZIP code"
                style={{
                  padding: '12px 16px',
                  border: '2px solid #e1e8ed',
                  borderRadius: '8px',
                  fontSize: '16px',
                  minWidth: '200px',
                  transition: 'border-color 0.3s ease',
                  outline: 'none'
                }}
                onFocus={(e) => e.target.style.borderColor = '#667eea'}
                onBlur={(e) => e.target.style.borderColor = '#e1e8ed'}
              />
              <button
                onClick={searchStores}
                disabled={storeSearchLoading}
                style={{
                  background: storeSearchLoading ? '#bdc3c7' : 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                  color: 'white',
                  padding: '12px 24px',
                  border: 'none',
                  borderRadius: '8px',
                  cursor: storeSearchLoading ? 'not-allowed' : 'pointer',
                  fontSize: '16px',
                  fontWeight: '600',
                  transition: 'all 0.3s ease',
                  boxShadow: storeSearchLoading ? 'none' : '0 4px 15px rgba(102, 126, 234, 0.4)'
                }}
              >
                {storeSearchLoading ? '🔍 Searching...' : '🔍 Find Stores'}
              </button>
            </div>
            <div style={{ fontSize: '14px', color: '#6c757d', fontStyle: 'italic', marginTop: '15px' }}>
              Don't shop at a Kroger's? Organize by category instead.
            </div>
          </div>

          {stores.length > 0 && (
            <div style={{ marginBottom: '15px' }}>
              <label style={{ display: 'block', marginBottom: '8px', fontWeight: '600', fontSize: '16px', color: '#2c3e50' }}>
                Select Store:
              </label>
              <select
                value={selectedStore ? selectedStore.id : ''}
                onChange={(e) => {
                  const store = stores.find(s => s.id === e.target.value);
                  setSelectedStore(store);
                }}
                style={{
                  padding: '12px 16px',
                  border: '2px solid #e1e8ed',
                  borderRadius: '8px',
                  fontSize: '16px',
                  width: '100%',
                  backgroundColor: 'white',
                  cursor: 'pointer',
                  outline: 'none'
                }}
              >
                {stores.map(store => (
                  <option key={store.id} value={store.id}>
                    {store.name} - {store.address} ({store.distance?.toFixed(1)} mi)
                  </option>
                ))}
              </select>
            </div>
          )}

          {selectedStore && (
            <div style={{ 
              marginTop: '15px', 
              padding: '15px', 
              background: 'linear-gradient(135deg, #a8edea 0%, #fed6e3 100%)', 
              borderRadius: '8px',
              border: '1px solid rgba(255,255,255,0.3)'
            }}>
              <p style={{ margin: '0', fontSize: '14px', color: '#2c3e50', fontWeight: '500' }}>
                ✅ Selected: <strong>{selectedStore.name}</strong><br/>
                📍 {selectedStore.address}
              </p>
            </div>
          )}
        </div>

        {/* Grocery List Input Section */}
        <div style={{ 
          marginBottom: '30px', 
          padding: '25px', 
          backgroundColor: '#f8f9fa', 
          borderRadius: '12px',
          boxShadow: '0 4px 15px rgba(0,0,0,0.05)',
          border: '1px solid #e9ecef'
        }}>
          <h3 style={{ margin: '0 0 20px 0', color: '#2c3e50', fontSize: '1.3rem', fontWeight: '600' }}>
            📝 Your Grocery List
          </h3>

          <div style={{ display: 'flex', gap: '25px', marginBottom: '20px' }}>
            {/* Text Input Section */}
            <div style={{ flex: '1' }}>
              <label style={{ display: 'block', marginBottom: '8px', fontWeight: '600', fontSize: '16px', color: '#2c3e50' }}>
                Type or Paste Items:
              </label>
              <textarea
                value={textInput}
                onChange={(e) => setTextInput(e.target.value)}
                placeholder="Enter grocery items, one per line:&#10;milk&#10;bread&#10;eggs&#10;apples"
                style={{
                  width: '100%',
                  height: '220px',
                  padding: '15px',
                  border: '2px solid #e1e8ed',
                  borderRadius: '8px',
                  fontSize: '16px',
                  fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif",
                  resize: 'vertical',
                  overflowY: 'auto',
                  outline: 'none',
                  transition: 'border-color 0.3s ease',
                  backgroundColor: 'white'
                }}
                onFocus={(e) => e.target.style.borderColor = '#667eea'}
                onBlur={(e) => e.target.style.borderColor = '#e1e8ed'}
              />
            </div>

            {/* File Upload Section */}
            <div style={{ flex: '1', paddingLeft: '25px' }}>
              <label style={{ display: 'block', marginBottom: '8px', fontWeight: '600', fontSize: '16px', color: '#2c3e50' }}>
                Or Upload Text File:
              </label>
              <input
                type="file"
                accept=".txt"
                onChange={handleFileUpload}
                style={{
                  width: '100%',
                  padding: '15px',
                  border: '2px solid #e1e8ed',
                  borderRadius: '8px',
                  fontSize: '16px',
                  backgroundColor: 'white',
                  cursor: 'pointer'
                }}
              />

              {file && (
                <div style={{ 
                  marginTop: '15px', 
                  padding: '10px 15px', 
                  backgroundColor: '#d4edda', 
                  borderRadius: '8px',
                  border: '1px solid #c3e6cb'
                }}>
                  <p style={{ margin: '0', fontSize: '14px', color: '#155724', fontWeight: '500' }}>
                    📄 Selected: <strong>{file.name}</strong>
                  </p>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Process Button */}
        <div style={{ textAlign: 'center', marginBottom: '30px' }}>
          <button
            onClick={processGroceryList}
            disabled={(!file && !textInput.trim()) || loading}
            style={{
              background: (!file && !textInput.trim()) || loading ? '#bdc3c7' : 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
              color: 'white',
              padding: '15px 40px',
              border: 'none',
              borderRadius: '50px',
              cursor: (!file && !textInput.trim()) || loading ? 'not-allowed' : 'pointer',
              fontSize: '18px',
              fontWeight: '600',
              transition: 'all 0.3s ease',
              boxShadow: (!file && !textInput.trim()) || loading ? 'none' : '0 8px 25px rgba(102, 126, 234, 0.4)',
              transform: (!file && !textInput.trim()) || loading ? 'none' : 'translateY(-2px)'
            }}
            onMouseEnter={(e) => {
              if (!((!file && !textInput.trim()) || loading)) {
                e.target.style.transform = 'translateY(-4px)';
                e.target.style.boxShadow = '0 12px 30px rgba(102, 126, 234, 0.5)';
              }
            }}
            onMouseLeave={(e) => {
              if (!((!file && !textInput.trim()) || loading)) {
                e.target.style.transform = 'translateY(-2px)';
                e.target.style.boxShadow = '0 8px 25px rgba(102, 126, 234, 0.4)';
              }
            }}
          >
            {loading ? '⚡ Processing...' : '🚀 Organize My List'}
          </button>
        </div>

        {/* Error Message */}
        {error && (
          <div style={{
            backgroundColor: '#ff6b6b',
            color: 'white',
            padding: '15px 20px',
            borderRadius: '8px',
            marginBottom: '30px',
            fontSize: '16px',
            fontWeight: '500',
            boxShadow: '0 4px 15px rgba(255, 107, 107, 0.3)'
          }}>
            ⚠️ {error}
          </div>
        )}

        {/* Results Section */}
        {groceryList && (
          <div style={{ 
            marginTop: '20px',
            padding: '25px', 
            backgroundColor: '#f8f9fa', 
            borderRadius: '12px',
            boxShadow: '0 4px 15px rgba(0,0,0,0.05)',
            border: '1px solid #e9ecef'
          }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px', flexWrap: 'wrap', gap: '15px' }}>
              <h3 style={{ margin: '0', color: '#2c3e50', fontSize: '1.3rem', fontWeight: '600' }}>
                🛒 Your Organized Shopping List
              </h3>
              <button
                onClick={copyToClipboard}
                style={{
                  background: 'linear-gradient(135deg, #4ecdc4 0%, #44a08d 100%)',
                  color: 'white',
                  padding: '10px 20px',
                  border: 'none',
                  borderRadius: '8px',
                  cursor: 'pointer',
                  fontSize: '14px',
                  fontWeight: '600',
                  transition: 'all 0.3s ease',
                  boxShadow: '0 4px 15px rgba(78, 205, 196, 0.4)'
                }}
              >
                📋 Copy to Clipboard
              </button>
            </div>

            <pre style={{
              backgroundColor: 'white',
              padding: '20px',
              borderRadius: '8px',
              border: '2px solid #e9ecef',
              whiteSpace: 'pre-wrap',
              fontFamily: "'JetBrains Mono', 'Consolas', 'Monaco', monospace",
              fontSize: '14px',
              lineHeight: '1.6',
              maxHeight: '500px',
              overflowY: 'auto',
              color: '#2c3e50'
            }}>
              {groceryList}
            </pre>
          </div>
        )}
      </div>
    </div>
  );
};

export default AisleFinder;
